/**
 * Global z-index registry.
 *
 * Tracks occupied z-index slots using a composite key `type@baseIndex`.
 * This allows the same ZIndexType to have multiple independent slot pools
 * when different base indexes are used (e.g., DROPDOWN inside modal A vs modal B).
 * When a slot is released (component unmounts), it becomes available for reuse,
 * keeping z-index values compact instead of endlessly incrementing.
 */
const registry = new Map<string, Set<number>>();

export type AcquireResult = { zIndex: number; registryKey: string; offset: number };

/** Acquire the lowest available z-index slot for the given type + base combination. */
export function acquire(type: string, baseIndex: number): AcquireResult {
  const registryKey = `${type}@${baseIndex}`;
  let slots = registry.get(registryKey);
  if (!slots) {
    slots = new Set();
    registry.set(registryKey, slots);
  }
  let offset = 0;
  while (slots.has(offset)) offset++;
  slots.add(offset);
  return { zIndex: baseIndex + offset, registryKey, offset };
}

/** Release a previously acquired slot back to the pool. */
export function release(registryKey: string, offset: number): void {
  const slots = registry.get(registryKey);
  if (!slots) return;
  slots.delete(offset);
  if (slots.size === 0) registry.delete(registryKey);
}

// ---------------------------------------------------------------------------
// Scroll lock
// ---------------------------------------------------------------------------

let scrollLockCount = 0;
let savedOverflow = '';

/** Increment scroll lock counter. Locks body scroll on first call. */
export function acquireScrollLock(): void {
  if (scrollLockCount === 0) {
    savedOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
  }
  scrollLockCount++;
}

/** Decrement scroll lock counter. Restores body scroll when counter reaches 0. */
export function releaseScrollLock(): void {
  if (scrollLockCount <= 0) return;
  scrollLockCount--;
  if (scrollLockCount === 0) {
    document.body.style.overflow = savedOverflow;
    savedOverflow = '';
  }
}
